import React, { useEffect, useState, useMemo } from 'react';
import { useDispatch, useSelector } from 'react-redux';
import { useSearchParams, useNavigate } from 'react-router-dom';
import { fetchProducts } from '../store/slices/productslice';
import ProductCard from '../components/product/productcart';
import LoadingSpinner from '../components/common/lodingspinner';
import { MOCK_PRODUCTS } from '../utils/mockproducts';
import { ChevronDown, ChevronUp, SlidersHorizontal, X } from 'lucide-react';

const SIDEBAR_CATEGORIES = {
    'LIVING ROOM': {
        'SOFAS': ['Fabric Sofas', 'Wooden Sofas', 'L-Shaped Sofas', 'Sofa Cum Beds', 'Recliners'],
        'SEATING': ['Lounge Chairs', 'Accent Chairs', 'Wing Chairs', 'Benches', 'Pouffes'],
        'TABLES': ['Coffee Tables', 'Side Tables', 'Console Tables', 'End Tables'],
        'STORAGE': ['TV Units', 'Bookshelves', 'Display Units', 'Shoe Racks']
    },
    'BEDROOM': {
        'BEDS': ['Solid Wood Beds', 'Upholstered Beds', 'Beds with Storage', 'King Size Beds', 'Queen Size Beds'],
        'STORAGE': ['Wardrobes', 'Chest of Drawers', 'Bedside Tables', 'Dressers'],
        'MATTRESSES': ['Memory Foam', 'Orthopedic', 'Dual Comfort', 'Coir Mattresses']
    },
    'DINING': {
        'DINING SETS': ['4 Seater Dining Sets', '6 Seater Dining Sets', '8 Seater Dining Sets', 'Extendable Dining'],
        'DINING STORAGE': ['Crockery Units', 'Kitchen Cabinets', 'Sideboards'],
        'DINING DECOR': ['Table Linens', 'Coasters', 'Dining Serveware']
    },
    'STUDY': {
        'STUDY TABLES': ['Solid Wood Tables', 'Computer Tables', 'Foldable Tables'],
        'OFFICE CHAIRS': ['Ergonomic Chairs', 'Executive Chairs', 'Study Chairs'],
        'OFFICE STORAGE': ['File Cabinets', 'Office Bookcases', 'Wall Shelves']
    }
};

const AllProductsPage = () => {
    const dispatch = useDispatch();
    const navigate = useNavigate();
    const [searchParams, setSearchParams] = useSearchParams();

    const [selectedCategory, setSelectedCategory] = useState(
        searchParams.get('category') || 'all'
    );
    const [activeAccordion, setActiveAccordion] = useState(null);
    const [sortBy, setSortBy] = useState(searchParams.get('sort') || 'newest');
    const [page, setPage] = useState(parseInt(searchParams.get('page')) || 1);

    // NEW: Mobile menu toggle state
    const [isMobileFiltersOpen, setIsMobileFiltersOpen] = useState(false);

    const { items: apiItems, loading, error } = useSelector(
        (state) => state.products
    );

    const items = useMemo(() => {
        return (apiItems && apiItems.length > 0) ? apiItems : MOCK_PRODUCTS;
    }, [apiItems]);

    const useMockData = useMemo(() => {
        return (!apiItems || apiItems.length === 0);
    }, [apiItems]);

    const filteredProducts = useMemo(() => {
        if (selectedCategory === 'all') return items;
        return items.filter(product => {
            const mainMatch = product.category?.toUpperCase() === selectedCategory.toUpperCase();
            const subMatch = product.subCategory?.toUpperCase() === selectedCategory.toUpperCase();
            return mainMatch || subMatch;
        });
    }, [items, selectedCategory]);

    const sortedProducts = useMemo(() => {
        return [...filteredProducts].sort((a, b) => {
            const priceA = a.variants?.[0]?.price || a.finalPrice || 0;
            const priceB = b.variants?.[0]?.price || b.finalPrice || 0;
            switch (sortBy) {
                case 'price_low': return priceA - priceB;
                case 'price_high': return priceB - priceA;
                case 'popular': return (b.rating || 0) - (a.rating || 0);
                case 'rating': return (b.rating || 0) - (a.rating || 0);
                case 'newest':
                default: return 0;
            }
        });
    }, [filteredProducts, sortBy]);

    const startIdx = (page - 1) * 20;
    const paginatedProducts = sortedProducts.slice(startIdx, startIdx + 20);
    const calculatedTotalPages = Math.ceil(sortedProducts.length / 20);

    useEffect(() => {
        const params = { page, limit: 20 };
        if (selectedCategory !== 'all') params.category = selectedCategory;
        if (sortBy !== 'newest') params.sort = sortBy;

        if (!useMockData) dispatch(fetchProducts(params));

        const newSearchParams = new URLSearchParams();
        if (selectedCategory !== 'all') newSearchParams.set('category', selectedCategory);
        if (sortBy !== 'newest') newSearchParams.set('sort', sortBy);
        if (page !== 1) newSearchParams.set('page', page);
        setSearchParams(newSearchParams);
    }, [dispatch, selectedCategory, sortBy, page, setSearchParams, useMockData]);

    const handleMainCategoryClick = (mainCat) => {
        setActiveAccordion(activeAccordion === mainCat ? null : mainCat);
        setSelectedCategory(mainCat);
        setPage(1);
        // Automatically close mobile menu when a category is selected
        if (window.innerWidth < 768) setIsMobileFiltersOpen(false);
    };

    const handleSubCategoryClick = (subCat) => {
        setSelectedCategory(subCat);
        setPage(1);
        if (window.innerWidth < 768) setIsMobileFiltersOpen(false);
    };

    const handleSortChange = (e) => {
        setSortBy(e.target.value);
        setPage(1);
    };

    const getDisplayCategory = () => {
        if (selectedCategory === 'all') return 'All Products';
        return selectedCategory.split(' ').map(word => word.charAt(0).toUpperCase() + word.slice(1).toLowerCase()).join(' ');
    };

    if (error && !useMockData) {
        return (
            <div className="bg-[#FAFAFA] min-h-screen py-12">
                <div className="container mx-auto px-4 text-center">
                    <h1 className="text-3xl font-bold text-red-600 mb-4">Error Loading Products</h1>
                    <p className="text-slate-600 mb-6">{error}</p>
                    <button onClick={() => window.location.reload()} className="bg-orange-600 text-white px-6 py-3 rounded-lg font-semibold hover:bg-orange-700 transition-colors">
                        Try Again
                    </button>
                </div>
            </div>
        );
    }

    return (
        <div className="bg-[#FAFAFA] min-h-screen font-sans">
            {/* Elegant Header */}
            <div className="bg-white border-b border-slate-200/60 py-8 md:py-10">
                <div className="container mx-auto px-4 md:px-8">
                    <div className="mb-4">
                        <button
                            onClick={() => navigate('/')}
                            className="text-slate-400 text-sm hover:text-orange-600 transition-colors flex items-center gap-2 group outline-none focus:outline-none"
                        >
                            <span className="transform group-hover:-translate-x-1 transition-transform">←</span>
                            Back to Home
                        </button>
                    </div>
                    <div className="flex flex-col md:flex-row md:items-end justify-between gap-4">
                        <div>
                            <h1 className="text-3xl md:text-5xl font-bold text-slate-900 mb-3 tracking-tight">
                                {getDisplayCategory()}
                            </h1>
                            <p className="text-slate-500 text-sm md:text-base font-medium">
                                Showing {paginatedProducts.length > 0 ? startIdx + 1 : 0} - {startIdx + paginatedProducts.length} of {sortedProducts.length} products
                            </p>
                        </div>

                        {/* Mobile Filter Toggle Button */}
                        <button
                            onClick={() => setIsMobileFiltersOpen(!isMobileFiltersOpen)}
                            className="md:hidden flex items-center justify-center gap-2 w-full bg-white border border-slate-200 text-slate-800 py-3 rounded-lg font-semibold shadow-sm hover:bg-slate-50 transition-colors"
                        >
                            <SlidersHorizontal size={18} />
                            {isMobileFiltersOpen ? 'Hide Filters' : 'Filters & Categories'}
                        </button>
                    </div>
                </div>
            </div>

            <div className="container mx-auto px-4 md:px-8 py-8 md:py-12">
                <div className="grid grid-cols-12 gap-8 lg:gap-10">

                    {/* LEFT SIDEBAR - Categories & Filters */}
                    <div className={`col-span-12 md:col-span-4 lg:col-span-3 space-y-6 md:block ${isMobileFiltersOpen ? 'block' : 'hidden'}`}>

                        {/* Premium Categories Box (Matching your image) */}
                        <div className="bg-white rounded-2xl shadow-[0_4px_24px_-8px_rgba(0,0,0,0.06)] border border-slate-100 p-6 md:sticky md:top-24">
                            <h3 className="text-[17px] font-bold text-slate-900 mb-6 tracking-tight">
                                Categories
                            </h3>
                            <div className="space-y-1">

                                {/* All Products Button */}
                                <button
                                    onClick={() => {
                                        setSelectedCategory('all');
                                        setActiveAccordion(null);
                                        setPage(1);
                                        if (window.innerWidth < 768) setIsMobileFiltersOpen(false);
                                    }}
                                    className="group w-full flex items-center justify-between py-3 px-3 rounded-lg transition-all duration-300 outline-none focus:outline-none"
                                >
                                    <span className={`text-[15px] transition-all duration-300 transform group-hover:translate-x-1 ${selectedCategory === 'all' ? 'text-orange-600 font-bold' : 'text-slate-600 font-medium group-hover:text-slate-900'
                                        }`}>
                                        All Products
                                    </span>
                                </button>

                                {/* Expandable Main Categories */}
                                {Object.keys(SIDEBAR_CATEGORIES).map((mainCat) => (
                                    <div key={mainCat} className="flex flex-col">
                                        <button
                                            onClick={() => handleMainCategoryClick(mainCat)}
                                            className={`group w-full flex items-center justify-between py-3 px-3 rounded-lg transition-all duration-300 outline-none focus:outline-none ${activeAccordion === mainCat ? 'bg-slate-50' : 'hover:bg-slate-50/50'
                                                }`}
                                        >
                                            <span className={`text-[15px] capitalize transition-all duration-300 transform group-hover:translate-x-1 ${activeAccordion === mainCat
                                                    ? 'text-orange-600 font-bold'
                                                    : 'text-slate-600 font-medium group-hover:text-slate-900'
                                                }`}>
                                                {mainCat.toLowerCase()}
                                            </span>
                                            <ChevronDown
                                                size={16}
                                                className={`transition-transform duration-300 ease-out ${activeAccordion === mainCat ? 'rotate-180 text-orange-600' : 'text-slate-400 group-hover:text-slate-600'
                                                    }`}
                                            />
                                        </button>

                                        {/* Subcategories */}
                                        <div className={`grid transition-all duration-300 ease-in-out ${activeAccordion === mainCat ? 'grid-rows-[1fr] opacity-100' : 'grid-rows-[0fr] opacity-0'
                                            }`}>
                                            <div className="overflow-hidden">
                                                <div className="pl-6 pr-2 space-y-5 py-3 border-l-2 border-slate-100 ml-5 my-2">
                                                    {Object.entries(SIDEBAR_CATEGORIES[mainCat]).map(([groupName, items]) => (
                                                        <div key={groupName}>
                                                            <h4 className="text-[10px] font-bold text-slate-400 uppercase tracking-widest mb-3">{groupName}</h4>
                                                            <ul className="space-y-1">
                                                                {items.map(item => (
                                                                    <li key={item}>
                                                                        <button
                                                                            onClick={() => handleSubCategoryClick(item)}
                                                                            className="group text-sm text-left w-full py-1.5 transition-all duration-300 outline-none focus:outline-none relative flex items-center"
                                                                        >
                                                                            {selectedCategory === item && (
                                                                                <span className="absolute -left-6 w-1.5 h-1.5 rounded-full bg-orange-500"></span>
                                                                            )}
                                                                            <span className={`block transform transition-transform duration-300 group-hover:translate-x-1.5 ${selectedCategory === item
                                                                                    ? 'text-orange-600 font-bold'
                                                                                    : 'text-slate-500 hover:text-slate-900'
                                                                                }`}>
                                                                                {item}
                                                                            </span>
                                                                        </button>
                                                                    </li>
                                                                ))}
                                                            </ul>
                                                        </div>
                                                    ))}
                                                </div>
                                            </div>
                                        </div>
                                    </div>
                                ))}
                            </div>
                        </div>

                        {/* Sort By Box */}
                        <div className="bg-white rounded-2xl shadow-[0_4px_24px_-8px_rgba(0,0,0,0.06)] border border-slate-100 p-6">
                            <h3 className="text-[17px] font-bold text-slate-900 mb-4 tracking-tight">Sort By</h3>
                            <div className="relative">
                                <select
                                    value={sortBy}
                                    onChange={handleSortChange}
                                    className="w-full px-4 py-3 border border-slate-200 rounded-lg text-slate-700 text-sm font-medium focus:outline-none focus:ring-2 focus:ring-orange-500/20 focus:border-orange-500 transition-all duration-300 cursor-pointer bg-white appearance-none"
                                >
                                    <option value="newest">Newest Arrivals</option>
                                    <option value="price_low">Price: Low to High</option>
                                    <option value="price_high">Price: High to Low</option>
                                    <option value="popular">Most Popular</option>
                                    <option value="rating">Top Rated</option>
                                </select>
                                <ChevronDown size={16} className="absolute right-4 top-1/2 -translate-y-1/2 text-slate-400 pointer-events-none" />
                            </div>
                        </div>
                    </div>

                    {/* RIGHT CONTENT - Products Grid */}
                    <div className="col-span-12 md:col-span-8 lg:col-span-9">
                        {loading && items.length === 0 ? (
                            <div className="flex justify-center items-center py-32">
                                <LoadingSpinner />
                            </div>
                        ) : paginatedProducts.length === 0 ? (
                            <div className="bg-white rounded-2xl shadow-[0_4px_24px_-8px_rgba(0,0,0,0.06)] border border-slate-100 p-16 text-center h-full flex flex-col items-center justify-center">
                                <div className="w-16 h-16 bg-slate-50 rounded-full flex items-center justify-center mb-6">
                                    <span className="text-2xl">🔍</span>
                                </div>
                                <h3 className="text-2xl font-bold text-slate-900 mb-3 tracking-tight">No Products Found</h3>
                                <p className="text-slate-500 mb-8 max-w-sm">We couldn't find any items matching your current filters. Try adjusting them or browse our full collection.</p>
                                <button
                                    onClick={() => {
                                        setSelectedCategory('all');
                                        setActiveAccordion(null);
                                    }}
                                    className="bg-slate-900 text-white px-8 py-3.5 rounded-lg font-bold hover:bg-orange-600 transition-colors duration-300 shadow-md"
                                >
                                    Clear All Filters
                                </button>
                            </div>
                        ) : (
                            <>
                                <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 xl:grid-cols-3 gap-6 lg:gap-8 mb-12">
                                    {paginatedProducts.map((product) => (
                                        <ProductCard key={product.id || product._id} product={product} />
                                    ))}
                                </div>

                                {/* Pagination */}
                                {calculatedTotalPages > 1 && (
                                    <div className="flex justify-center items-center gap-2 py-8 border-t border-slate-200/60 mt-8">
                                        <button
                                            onClick={() => setPage(Math.max(1, page - 1))}
                                            disabled={page === 1}
                                            className="px-4 py-2.5 border border-slate-200 rounded-lg text-slate-600 font-medium hover:border-slate-300 hover:bg-slate-50 disabled:opacity-40 disabled:cursor-not-allowed transition-all duration-300"
                                        >
                                            Previous
                                        </button>

                                        {Array.from({ length: Math.min(calculatedTotalPages, 5) }, (_, i) => {
                                            const pageNum = page > 3 ? page - 2 + i : i + 1;
                                            return pageNum <= calculatedTotalPages ? pageNum : null;
                                        }).map(
                                            (p) => p && (
                                                <button
                                                    key={p}
                                                    onClick={() => setPage(p)}
                                                    className={`w-10 h-10 flex items-center justify-center rounded-lg transition-all duration-300 font-semibold ${page === p ? 'bg-slate-900 text-white shadow-md' : 'text-slate-600 hover:bg-slate-100'
                                                        }`}
                                                >
                                                    {p}
                                                </button>
                                            )
                                        )}

                                        <button
                                            onClick={() => setPage(Math.min(calculatedTotalPages, page + 1))}
                                            disabled={page === calculatedTotalPages}
                                            className="px-4 py-2.5 border border-slate-200 rounded-lg text-slate-600 font-medium hover:border-slate-300 hover:bg-slate-50 disabled:opacity-40 disabled:cursor-not-allowed transition-all duration-300"
                                        >
                                            Next
                                        </button>
                                    </div>
                                )}
                            </>
                        )}
                    </div>
                </div>
            </div>
        </div>
    );
};

export default AllProductsPage;
